import{_ as e}from"./chunks/logo.PPNoggWL.js";import{_ as a,o,c as s,ag as i}from"./chunks/framework.wGDfT7ie.js";const n="/docs/assets/auth_setup_doc.FDS2LxUu.mp4",f=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"doc","next":{"text":"Configurations","link":"/pages/installation/configurations"},"prev":{"text":"Troubleshooting","link":"/pages/installation/troubleshooting"}},"headers":[],"relativePath":"pages/installation/post-installation.md","filePath":"pages/installation/post-installation.md"}'),r={name:"pages/installation/post-installation.md"};function c(l,t,p,u,h,d){return o(),s("div",null,[...t[0]||(t[0]=[i('<img src="'+e+'" alt="AtmosphericX Logo" width="200" style="display:block;margin-left:auto;margin-right:auto;"><small class="page-author">Written By: KiyoWx</small><br><small class="last-updated">Last Updated: Jan 23rd, 2026</small><h2 id="post-installation-setup" tabindex="-1">Post-Installation Setup <a class="header-anchor" href="#post-installation-setup" aria-label="Permalink to &quot;Post-Installation Setup&quot;">​</a></h2><p>Congratulations on successfully installing AtmosphericX! This guide will walk you through the essential post installation steps to get your AtmosphericX instance up and running smoothly. These steps include initial configuration, setting up user accounts, and verifying that all components are functioning correctly.</p><h2 id="accessing-the-web-interface" tabindex="-1">Accessing the web interface <a class="header-anchor" href="#accessing-the-web-interface" aria-label="Permalink to &quot;Accessing the web interface&quot;">​</a></h2><p>AtmosphericX provides a web based interface for easy management. To access the web interface, open your preferred web browser and navigate to <code>http://localhost</code> or <code>http://&lt;your-server-ip&gt;</code> if you are accessing it remotely.</p><div class="tip custom-block"><p class="custom-block-title">Note</p><p>During your first launch, you may be prompted to complete an initial setup wizard. Follow the on-screen instructions to configure basic settings such as admin account creation.</p></div><h3 id="authentication-setup" tabindex="-1">Authentication Setup <a class="header-anchor" href="#authentication-setup" aria-label="Permalink to &quot;Authentication Setup&quot;">​</a></h3><p>During the initial setup you will be prompted to create an administrator account with full access to AtmosphericX. When that prompt appears, enter the randomly generated authentication key that the setup page provides. The key is created automatically each time you open the setup page, remains valid only for the current setup session, and appears <strong>once</strong> in the console, so be sure to copy it before closing or refreshing the page. This step helps ensure secure access while your administrative account is being created.</p><p>Once you are authenticated, you can proceed to create your admin account by providing a username and password. Make sure to choose a strong password to enhance security. A full video walkthrough of the authentication setup process is provided below for your convenience:</p><video controls><source src="'+n+'" type="video/mp4"></video><small>Video: AtmosphericX Authentication Setup Walkthrough</small><h2 id="todo-dashboard-must-be-completed-first" tabindex="-1">TODO (Dashboard must be completed first) <a class="header-anchor" href="#todo-dashboard-must-be-completed-first" aria-label="Permalink to &quot;TODO (Dashboard must be completed first)&quot;">​</a></h2>',15)])])}const b=a(r,[["render",c]]);export{f as __pageData,b as default};
